import { clamp, round } from './utils';

export function formatTokens(tokens?: number): string {
  if (tokens === undefined || Number.isNaN(tokens)) return '—';
  if (tokens >= 1_000_000) return `${round(tokens / 1_000_000, 2)}M`;
  if (tokens >= 1_000) return `${round(tokens / 1_000, 1)}K`;
  return `${Math.round(tokens)}`;
}

export function formatPercent(value?: number): string {
  if (value === undefined || Number.isNaN(value)) return '—';
  return `${round(clamp(value, 0, 100), value > 10 ? 0 : 1)}%`;
}

export function formatCurrency(value?: number): string {
  if (value === undefined || Number.isNaN(value)) return '—';
  return new Intl.NumberFormat(undefined, {
    style: 'currency',
    currency: 'USD',
    minimumFractionDigits: value < 1 ? 2 : 0,
    maximumFractionDigits: value < 1 ? 2 : 0
  }).format(value);
}

export function formatDateTime(timestamp?: number): string {
  if (!timestamp) return 'Unknown';
  return new Intl.DateTimeFormat(undefined, {
    month: 'short',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit'
  }).format(new Date(timestamp));
}

export function formatClock(timestamp?: number): string {
  if (!timestamp) return 'Unknown';
  return new Intl.DateTimeFormat(undefined, {
    hour: 'numeric',
    minute: '2-digit'
  }).format(new Date(timestamp));
}

export function formatDuration(ms?: number): string {
  if (ms === undefined) return '—';
  if (ms <= 0) return 'now';
  const totalSeconds = Math.floor(ms / 1000);
  const days = Math.floor(totalSeconds / 86400);
  const hours = Math.floor((totalSeconds % 86400) / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;
  if (days > 0) return `${days}d ${hours}h`;
  if (hours > 0) return `${hours}h ${minutes}m`;
  if (minutes > 0) return `${minutes}m ${seconds}s`;
  return `${seconds}s`;
}

export function formatRelativeTime(target: number): string {
  const diff = target - Date.now();
  const formatter = new Intl.RelativeTimeFormat(undefined, { numeric: 'auto' });
  const minutes = Math.round(diff / 60_000);
  if (Math.abs(minutes) < 60) return formatter.format(minutes, 'minute');
  const hours = Math.round(diff / 3_600_000);
  if (Math.abs(hours) < 48) return formatter.format(hours, 'hour');
  const days = Math.round(diff / 86_400_000);
  return formatter.format(days, 'day');
}
