import { SITE_LABELS } from '../lib/constants';
import { formatClock, formatCurrency, formatDateTime, formatTokens } from '../lib/format';
import { sendRuntimeMessage } from '../lib/runtime';
import type { AppSnapshot } from '../types';
import { truncate } from '../lib/utils';
import { renderBarList, renderSparkline } from '../ui/charts';

const metrics = document.querySelector<HTMLElement>('#metrics')!;
const dailyChart = document.querySelector<HTMLElement>('#daily-chart')!;
const weeklyChart = document.querySelector<HTMLElement>('#weekly-chart')!;
const siteBreakdown = document.querySelector<HTMLElement>('#site-breakdown')!;
const modelBreakdown = document.querySelector<HTMLElement>('#model-breakdown')!;
const recentThreads = document.querySelector<HTMLElement>('#recent-threads')!;
const timeline = document.querySelector<HTMLElement>('#timeline')!;
const anomalies = document.querySelector<HTMLElement>('#anomalies')!;
const changeCard = document.querySelector<HTMLElement>('#change-card')!;

function download(filename: string, content: string, type: string): void {
  const blob = new Blob([content], { type });
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement('a');
  anchor.href = url;
  anchor.download = filename;
  anchor.click();
  URL.revokeObjectURL(url);
}

function renderMetrics(snapshot: AppSnapshot): void {
  const peakDay = snapshot.analytics.peakDay;
  metrics.innerHTML = [
    { label: 'Today', value: formatTokens(snapshot.summary.tokensToday) },
    { label: '7-day tokens', value: formatTokens(snapshot.summary.tokensThisWeek) },
    { label: '7-day cost', value: formatCurrency(snapshot.summary.costThisWeek) },
    { label: 'Burn rate / day', value: formatTokens(snapshot.analytics.burnRate) },
    { label: 'Streak', value: `${snapshot.analytics.streakDays} days` },
    { label: 'Average prompt', value: formatTokens(snapshot.analytics.averagePromptTokens) },
    { label: 'Peak day', value: peakDay ? `${formatTokens(peakDay.tokens)} • ${peakDay.date}` : '—' },
    { label: 'Active sites', value: `${snapshot.summary.activeSites}` },
    { label: 'Prompts today', value: `${snapshot.summary.promptsToday}` },
    { label: 'Recent threads', value: `${snapshot.recentThreads.length}` }
  ]
    .map(
      (item) => `
        <article class="metric-card">
          <span>${item.label}</span>
          <strong>${item.value}</strong>
        </article>
      `
    )
    .join('');
}

function renderChangeSummary(snapshot: AppSnapshot): void {
  const [latest, previous] = snapshot.analytics.timeline;
  if (!latest) {
    changeCard.innerHTML = '<div class="empty-chart">No session history yet. Send a few prompts on a supported AI site to populate the dashboard.</div>';
    return;
  }
  const delta = previous ? latest.totalTokens - previous.totalTokens : latest.totalTokens;
  const direction = delta >= 0 ? 'more' : 'fewer';
  changeCard.innerHTML = `
    <div class="copy-card">
      <strong>${SITE_LABELS[latest.site]} • ${latest.model}</strong>
      <p>The most recent exchange used ${formatTokens(latest.totalTokens)} tokens, which is ${formatTokens(Math.abs(delta))} ${direction} than the one before it.</p>
    </div>
    <div class="copy-card">
      <strong>Current risk</strong>
      <p>${snapshot.currentSession?.quota.status === 'warning' || snapshot.currentSession?.quota.status === 'limited'
        ? `The active session is approaching its limit, with reset ${snapshot.currentSession.quota.nextReset?.localLabel ?? 'unknown'}.`
        : 'No immediate quota pressure detected on the active session.'}</p>
    </div>
    <div class="copy-card">
      <strong>Optimization signal</strong>
      <p>${snapshot.currentSession?.currentEstimate.suggestions[0]?.description ?? 'Prompts look healthy. Keep an eye on long pasted context and code blocks.'}</p>
    </div>
  `;
}

async function render(): Promise<void> {
  const snapshot = await sendRuntimeMessage<AppSnapshot>({ type: 'get-snapshot' });
  renderMetrics(snapshot);
  renderSparkline(
    dailyChart,
    snapshot.analytics.byDay.map((day) => day.tokens),
    snapshot.analytics.byDay.map((day) => day.date)
  );
  renderBarList(
    weeklyChart,
    snapshot.analytics.byWeek.map((week) => ({ label: week.date, value: week.tokens, meta: `${week.prompts} prompts • ${formatCurrency(week.cost)}` }))
  );
  renderBarList(
    siteBreakdown,
    snapshot.analytics.bySite.map((site) => ({ label: site.label, value: site.tokens, meta: `${site.prompts} prompts • ${formatCurrency(site.cost)}` }))
  );
  renderBarList(
    modelBreakdown,
    snapshot.analytics.byModel.map((model) => ({ label: model.label, value: model.tokens, meta: `${model.prompts} prompts • ${formatCurrency(model.cost)}` }))
  );

  recentThreads.innerHTML = snapshot.recentThreads.length
    ? snapshot.recentThreads
        .map(
          (thread) => `
            <div class="copy-card">
              <strong>${SITE_LABELS[thread.site]} • ${thread.model}</strong>
              <p>${formatTokens(thread.totalTokens)} tokens across ${thread.messageCount} messages. Updated ${formatClock(thread.lastUpdated)}.</p>
            </div>
          `
        )
        .join('')
    : '<div class="empty-chart">No tracked threads yet.</div>';

  timeline.innerHTML = snapshot.analytics.timeline.length
    ? snapshot.analytics.timeline
        .map(
          (event) => `
            <div class="timeline-item">
              <strong>${SITE_LABELS[event.site]} • ${event.model}</strong>
              <p>${truncate(event.promptPreview, 180)}</p>
              <small>${formatDateTime(event.timestamp)} • ${formatTokens(event.totalTokens)} tokens • ${event.status}</small>
            </div>
          `
        )
        .join('')
    : '<div class="empty-chart">No timeline yet.</div>';

  anomalies.innerHTML = snapshot.analytics.anomalies.length
    ? snapshot.analytics.anomalies
        .map(
          (event) => `
            <div class="copy-card">
              <strong>${SITE_LABELS[event.site]} spike • ${formatTokens(event.totalTokens)}</strong>
              <p>${truncate(event.promptPreview, 180)}</p>
            </div>
          `
        )
        .join('')
    : '<div class="empty-chart">No anomalies detected.</div>';

  renderChangeSummary(snapshot);

  document.querySelector<HTMLButtonElement>('#export-json-btn')!.onclick = async () => {
    const payload = await sendRuntimeMessage({ type: 'export-data' });
    download('yor-token-usage-export.json', JSON.stringify(payload, null, 2), 'application/json');
  };

  document.querySelector<HTMLButtonElement>('#export-csv-btn')!.onclick = () => {
    const rows = ['date,tokens,prompts,cost', ...snapshot.analytics.byDay.map((day) => `${day.date},${day.tokens},${day.prompts},${day.cost.toFixed(4)}`)];
    download('yor-token-usage-daily.csv', rows.join('\n'), 'text/csv');
  };

  document.querySelector<HTMLButtonElement>('#settings-btn')!.onclick = async () => {
    await chrome.runtime.openOptionsPage();
  };
}

void render();
